import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"千金方","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/02-魏晋隋唐/04-千金方（孙思邈）.md","filePath":"tcm-data/02-魏晋隋唐/04-千金方（孙思邈）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/02-魏晋隋唐/04-千金方（孙思邈）.md"};function n(i,t,d,s,h,u){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="千金方" tabindex="-1">千金方 <a class="header-anchor" href="#千金方" aria-label="Permalink to &quot;千金方&quot;">​</a></h1><blockquote><p>孙思邈（541-682年），陕西耀县人，享年141岁 药王，《千金要方》+《千金翼方》合称《千金方》 中医史上规模最大的临床百科全书</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：《千金要方》652年（孙思邈时年111岁），《千金翼方》682年（141岁）</li><li><strong>卷数</strong>：《要方》30卷，《翼方》30卷，共60卷</li><li><strong>篇量</strong>：载方6500余首</li><li><strong>学术地位</strong>：「一部书囊括唐以前全部医学成就」</li></ul><h3 id="什么是-千金" tabindex="-1">什么是&quot;千金&quot; <a class="header-anchor" href="#什么是-千金" aria-label="Permalink to &quot;什么是&quot;千金&quot;&quot;">​</a></h3><blockquote><p><strong>「人命至重，有贵千金，一方济之，德逾于此。」</strong></p></blockquote><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-大医精诚-——-医德规范-中国最早的医德专论" tabindex="-1">1. 大医精诚 —— 医德规范（中国最早的医德专论） <a class="header-anchor" href="#_1-大医精诚-——-医德规范-中国最早的医德专论" aria-label="Permalink to &quot;1. 大医精诚 —— 医德规范（中国最早的医德专论）&quot;">​</a></h3><blockquote><p><strong>「凡大医治病，必当安神定志，无欲无求，先发大慈恻隐之心，誓愿普救含灵之苦。」</strong><strong>「若有疾厄来求救者，不得问其贵贱贫富，长幼妍蚩，怨亲善友，华夷愚智，普同一等，皆如至亲之想。」</strong><strong>「见彼苦恼，若己有之，深心凄怆，勿避险巇、昼夜寒暑、饥渴疲劳，一心赴救，无作功夫形迹之心。」</strong></p></blockquote><p><strong>这两段文字（大医习业+大医精诚）至今仍刻在中医院校的墙壁上。</strong></p><h3 id="_2-脏腑分类" tabindex="-1">2. 脏腑分类 <a class="header-anchor" href="#_2-脏腑分类" aria-label="Permalink to &quot;2. 脏腑分类&quot;">​</a></h3><p>首次按<strong>五脏六腑</strong>分类疾病——每脏先讲生理，再列病证和方剂。这种结构对后世影响深远。</p><h3 id="_3-妇人方独立成篇" tabindex="-1">3. 妇人方独立成篇 <a class="header-anchor" href="#_3-妇人方独立成篇" aria-label="Permalink to &quot;3. 妇人方独立成篇&quot;">​</a></h3><p>孙思邈认为：「妇人之病，比之男子，十倍难疗。」 在《千金要方》中将<strong>妇人方</strong>列于卷首（卷2-4），这是中医史上第一次将妇科独立成篇。</p><h3 id="_4-食治为先" tabindex="-1">4. 食治为先 <a class="header-anchor" href="#_4-食治为先" aria-label="Permalink to &quot;4. 食治为先&quot;">​</a></h3><blockquote><p><strong>「夫为医者，当须先洞晓病源，知其所犯，以食治之，食疗不愈，然后命药。」</strong></p></blockquote><p>孙思邈是<strong>食疗</strong>的积极倡导者。他的弟子孟诜据此写了《食疗本草》。</p><h3 id="_5-养老与养生" tabindex="-1">5. 养老与养生 <a class="header-anchor" href="#_5-养老与养生" aria-label="Permalink to &quot;5. 养老与养生&quot;">​</a></h3><ul><li>卷27专论<strong>养性</strong></li><li>提出「<strong>五难</strong>」：名利不去为一难，喜怒不除为二难，声色不去为三难，滋味不绝为四难，神虑精散为五难</li><li>创制**&quot;服食&quot;养生法**</li></ul><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;">小续命汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">麻黄、桂枝、杏仁、甘草、川芎、防风、防己、人参、黄芩、附子、芍药、生姜</td><td style="text-align:left;">中风</td></tr><tr><td style="text-align:left;">温脾汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">附子、大黄、干姜、人参、甘草</td><td style="text-align:left;">冷积便秘</td></tr><tr><td style="text-align:left;">独活寄生汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">独活、桑寄生、杜仲、牛膝、细辛、秦艽、茯苓、桂心、防风、川芎、人参、甘草、当归、芍药、干地黄</td><td style="text-align:left;">痹证（腰膝冷痛）</td></tr><tr><td style="text-align:left;">犀角地黄汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">犀角、生地、芍药、丹皮</td><td style="text-align:left;">热入血分</td></tr><tr><td style="text-align:left;">苇茎汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">苇茎、薏苡仁、桃仁、冬瓜仁</td><td style="text-align:left;">肺痈</td></tr><tr><td style="text-align:left;">紫雪</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">多种矿物药</td><td style="text-align:left;">高热神昏</td></tr><tr><td style="text-align:left;">温胆汤</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">半夏、枳实、竹茹、陈皮、甘草、生姜</td><td style="text-align:left;">胆虚不眠</td></tr><tr><td style="text-align:left;">磁朱丸</td><td style="text-align:left;">《千金要方》</td><td style="text-align:left;">磁石、朱砂、神曲</td><td style="text-align:left;">心悸失眠、目昏</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><blockquote><p><strong>「凡大医治病，必当安神定志，无欲无求。」</strong></p></blockquote><blockquote><p><strong>「人命至重，有贵千金，一方济之，德逾于此。」</strong></p></blockquote><blockquote><p><strong>「上医医国，中医医人，下医医病。」</strong></p></blockquote><blockquote><p><strong>「胆欲大而心欲小，智欲圆而行欲方。」</strong></p></blockquote><blockquote><p><strong>「养生有五难：名利不去为一难，喜怒不除为二难，声色不去为三难，滋味不绝为四难，神虑精散为五难。」</strong></p></blockquote><blockquote><p><strong>「善养性者，则治未病之病。」</strong></p></blockquote><blockquote><p><strong>「安身之本，必资于食；救疾之速，必凭于药。」</strong></p></blockquote><blockquote><p><strong>「夫为医者，当须先洞晓病源，知其所犯，以食治之，食疗不愈，然后命药。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="妇科学" tabindex="-1">妇科学 <a class="header-anchor" href="#妇科学" aria-label="Permalink to &quot;妇科学&quot;">​</a></h3><ul><li>妇人方独立 → 启发后世《妇人大全良方》（陈自明）、《傅青主女科》</li></ul><h3 id="食疗" tabindex="-1">食疗 <a class="header-anchor" href="#食疗" aria-label="Permalink to &quot;食疗&quot;">​</a></h3><ul><li>弟子孟诜著《食疗本草》</li><li>孙思邈的食治思想 → 李东垣《脾胃论》 → 黄元御&quot;崇阳补土&quot;</li></ul><h3 id="针灸" tabindex="-1">针灸 <a class="header-anchor" href="#针灸" aria-label="Permalink to &quot;针灸&quot;">​</a></h3><ul><li>《千金方》绘有 <strong>&quot;明堂三人图&quot;</strong> （最早的经络挂图）</li></ul><h3 id="医德" tabindex="-1">医德 <a class="header-anchor" href="#医德" aria-label="Permalink to &quot;医德&quot;">​</a></h3><ul><li>&quot;大医精诚&quot;至今仍是中医界的精神纲领</li></ul><h3 id="黄元御" tabindex="-1">黄元御 <a class="header-anchor" href="#黄元御" aria-label="Permalink to &quot;黄元御&quot;">​</a></h3><ul><li>孙思邈的脏腑分类法和养生思想对黄元御&quot;四圣心源&quot;有间接影响</li></ul><hr><p><em>本条目为精简框架版。可在后续扩展至各科（尤其妇科、儿科、养生）的专题。</em></p>',48)])])}const q=e(r,[["render",n]]);export{c as __pageData,q as default};
